import{_ as l,o as r,c as a,a2 as o}from"./chunks/framework.BWuWLRhz.js";const c=JSON.parse('{"title":"计算机基础","description":"","frontmatter":{},"headers":[],"relativePath":"计算机基础/计算机基础.md","filePath":"计算机基础/计算机基础.md","lastUpdated":null}'),i={name:"计算机基础/计算机基础.md"};function n(s,t,e,g,p,h){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="计算机基础" tabindex="-1">计算机基础 <a class="header-anchor" href="#计算机基础" aria-label="Permalink to &quot;计算机基础&quot;">​</a></h1><h2 id="操作系统" tabindex="-1">操作系统 <a class="header-anchor" href="#操作系统" aria-label="Permalink to &quot;操作系统&quot;">​</a></h2><h3 id="进程" tabindex="-1">进程 <a class="header-anchor" href="#进程" aria-label="Permalink to &quot;进程&quot;">​</a></h3><p><strong>定义</strong>：</p><ul><li>进程是程序的一次执行。</li><li>进程是可以并行执行的计算。</li><li>进程是一个程序与其使用的数据在处理机上顺序执行时发生的活动。</li><li>进程是程序在一个数据集合上的运行过程。</li><li>它是系统进行资源分配和调度的一个独立单位。</li></ul><p><strong>进程的特征</strong>：</p><ul><li>动态性：进程是程序的一次执行，是程序在数据集合上的运行过程。</li><li>并发性：多个进程可以并发执行。</li><li>独立性：进程是系统进行资源分配和调度的一个独立单位。</li><li>异步性：进程是异步执行的，进程的执行顺序是不确定的。</li><li>结构性：进程由程序、数据和进程控制块组成。</li></ul><p><strong>进程和应用程序的区别</strong>：</p><ul><li>程序是永存的；进程是暂时的，是程序在数据集上的一次执行，有创建有撤销，存在是暂时的；</li><li>程序是静态的观念，进程是动态的观念；</li><li>进程具有并发性，而程序没有；</li><li>进程是竞争计算机资源的基本单位，程序不是。</li><li>进程和程序不是一一对应的： 一个程序可对应多个进程即多个进程可执行同一程序； 一个进程可以执行一个或几个程序</li></ul><h4 id="进程间的通信" tabindex="-1">进程间的通信 <a class="header-anchor" href="#进程间的通信" aria-label="Permalink to &quot;进程间的通信&quot;">​</a></h4><p>进程间通信的方式：</p><ul><li><strong>管道</strong>：管道是一种半双工的通信方式，数据只能单向流动，而且只能在具有亲缘关系的进程间使用。进程的亲缘关系通常是指父子进程关系。</li><li><strong>套接字</strong>：套接字是一种用于网络通信的通用接口，不仅可以用于不同主机之间的进程通信，还可以用于同一主机上的进程通信。套接字提供了一种灵活的进程间通信方式，允许进程在不同主机之间通过网络进行通信。</li><li><strong>消息队列</strong>：消息队列是由消息的链表，存放在内核中并由消息队列标识符标识。消息队列克服了信号传递信息少、管道只能承载无格式字节流以及缓冲区大小受限等缺点。</li><li><strong>共享内存</strong>：共享内存是一种高效的进程间通信方式，允许多个进程共享同一块内存区域。共享内存适用于需要频繁交换大量数据的进程间通信场景</li><li><strong>信号量</strong>：信号量是一种用于进程间同步和互斥的机制。信号量通常用于控制对共享资源的访问，以防止多个进程同时访问共享资源。</li></ul><h3 id="线程" tabindex="-1">线程 <a class="header-anchor" href="#线程" aria-label="Permalink to &quot;线程&quot;">​</a></h3><p>线程是进程中的⼀个执⾏单元，负责当前进程中程序的执⾏，⼀个进程中⾄少有⼀个线程。⼀个进程中是可以有多个线程的，这个应⽤程序也可以称之为多线程程序。 <strong>进程和线程的区别</strong>： 进程是资源分配的基本单位；线程是程序执行的基本单位。 进程拥有自己的资源空间，没启动一个进程，系统就会为它分配地址空间；而线程与CPU资源分配无关，多个线程共享同一进程内的资源，使用相同的地址空间。 一个进程可以包含若干个线程。 <strong>线程间的通信</strong>：</p><ul><li><strong>共享内存</strong>：线程之间共享程序的公共状态，线程之间通过读-写内存中的公共状态来隐式通信。</li><li><strong>互斥量</strong>：互斥量是一种同步机制，用于保护共享资源，防止多个线程同时访问共享资源。互斥量提供了一种排他的访问机制，同一时间只允许一个线程访问共享资源。</li><li><strong>条件变量</strong>：条件变量是一种同步机制，用于线程之间的通信。条件变量允许线程在满足特定条件时等待，当条件不满足时，线程会被阻塞，直到条件满足时被唤醒。</li></ul><h3 id="死锁" tabindex="-1">死锁 <a class="header-anchor" href="#死锁" aria-label="Permalink to &quot;死锁&quot;">​</a></h3><p>死锁的四个条件： <strong>互斥条件</strong>：资源是独占的且排他使用，进程互斥使用资源，即任意时刻一个资源只能给一个进程使用，其他进程若申请一个资源，而该资源被另一进程占有时，则申请者等待直到资源被占有者释放。 <strong>不可剥夺条件</strong>：进程所获得的资源在未使用完毕之前，不被其他进程强行剥夺，而只能由获得该资源的进程资源释放。 <strong>请求和保持条件</strong>：进程每次申请它所需要的一部分资源，在申请新的资源的同时，继续占用已分配到的资源。 <strong>循环等待条件</strong>：在发生死锁时必然存在一个进程等待队列{P1,P2,…,Pn},其中P1等待P2占有的资源，P2等待P3占有的资源，…，Pn等待P1占有的资源，形成一个进程等待环路，环路中每一个进程所占有的资源同时被另一个申请，也就是前一个进程占有后一个进程所深情地资源。</p><h3 id="函数调用过程" tabindex="-1">函数调用过程 <a class="header-anchor" href="#函数调用过程" aria-label="Permalink to &quot;函数调用过程&quot;">​</a></h3><p>参数入栈、保护现场、函数跳转、恢复现场</p><ol><li><p><strong>函数调用触发</strong>： 当程序执行到函数调用语句时，会将控制权转移到被调用函数的代码块。</p></li><li><p><strong>保护上下文</strong>：</p></li></ol><ul><li>调用函数前，当前函数的执行现场（上下文）需要保存，以便在函数调用结束后能够恢复。包括函数返回地址、当前函数的局部变量、寄存器的状态等。</li><li>这些信息通常被保存在调用栈（call stack）上。</li></ul><ol start="3"><li><p><strong>传递参数</strong>： 将调用函数的参数传递给被调用函数。参数的传递方式有值传递、引用传递、指针传递等。</p></li><li><p><strong>分配栈空间</strong>： 为被调用函数分配栈空间。通常在栈上分配局部变量和函数的执行过程中需要的其他临时数据。</p></li><li><p><strong>跳转到被调用函数</strong>： 使用跳转指令（例如call指令）将程序控制权转移到被调用函数的入口点。</p></li><li><p><strong>执行被调用函数</strong>： 被调用函数开始执行，执行函数体中的代码。在函数内部，局部变量和参数通常被存储在栈上。</p></li><li><p><strong>函数返回</strong>： 被调用函数执行完毕后，将返回值存储在指定的寄存器中或通过栈传递给调用函数。</p></li><li><p><strong>清理栈空间</strong>： 被调用函数执行完毕后，需要清理栈上分配的局部变量等信息。</p></li><li><p><strong>恢复上下文</strong>： 恢复调用函数的上下文，包括返回地址等信息。</p></li><li><p><strong>返回到调用点</strong>： 使用返回指令（例如ret指令）将程序控制权返回到调用函数的下一条指令，继续执行。</p></li></ol><h3 id="大小端" tabindex="-1">大小端 <a class="header-anchor" href="#大小端" aria-label="Permalink to &quot;大小端&quot;">​</a></h3><p>0x12345678按大小端在内存中的排布如下：</p><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/blogs/20240104195709.png" alt="20240104195709"> 小端模式：高字节<strong>0x12</strong>在高地址<strong>0x4003</strong> 大端模式：高字节<strong>0x12</strong>在低地址<strong>0x4000</strong><strong>Windows是小端存储</strong></p><h2 id="计算机网络" tabindex="-1">计算机网络 <a class="header-anchor" href="#计算机网络" aria-label="Permalink to &quot;计算机网络&quot;">​</a></h2><p>TCP/IP协议与七层ISO模型</p><p><img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20240328193233.png" alt="20240328193233"></p><h3 id="tcp协议" tabindex="-1">TCP协议 <a class="header-anchor" href="#tcp协议" aria-label="Permalink to &quot;TCP协议&quot;">​</a></h3><p>TCP协议是一种面向连接的、可靠的、基于字节流的传输层协议。TCP协议提供了可靠的数据传输服务，确保数据的完整性、顺序性和可靠性。</p><h4 id="三次握手" tabindex="-1">三次握手 <a class="header-anchor" href="#三次握手" aria-label="Permalink to &quot;三次握手&quot;">​</a></h4><p><img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20240329130049.png" alt="20240329130049"><strong>为什么需要三次握手？</strong> 防止已过期的连接请求报文突然又传送到服务器，因而产生错误。 形象一点的解释： 三次握手的本质是让双方都能明确自己和对方的发送和接收能力是正常的，从而建立起可靠的通信。 <strong>三次握手过程</strong>：</p><ol><li>客户端发送请求报文，此时的客户端什么都无法确认，服务器可以确认自己的接收能力和对方发送能力正常。</li><li>服务端接收到请求报文后，发送确认报文。客户端收到确认报文后，可以确认自己的发送能力和接收能力正常，对方的发送和接收能力正常。</li><li>客户端发送确认报文，服务端收到确认报文后，可以确认自己的发送和接收能力正常，对方的发送和接收能力正常。 因此只有经过三次握手，才能让双方都确认自己的发送和接受能力全部正常。 类似以下过程：</li></ol><blockquote><p>三次握手 “你能听见我说话吗？” “我能听见，你能听见我说话吗？” “我能听见” 开始对话.....</p></blockquote><h4 id="四次挥手" tabindex="-1">四次挥手 <a class="header-anchor" href="#四次挥手" aria-label="Permalink to &quot;四次挥手&quot;">​</a></h4><p><img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20240329130031.png" alt="20240329130031"><strong>为什么 TCP 关闭连接为什么要四次而不是三次？</strong> 服务器在收到客户端的 FIN 报文段后，可能还有一些数据要传输，所以不能马上关闭连接，但是会做出应答，返回 ACK 报文段，接下来可能会继续发送数据，在数据发送完后，服务器会向客户单发送 FIN 报文，表示数据已经发送完毕，请求关闭连接，然后客户端再做出应答，因此一共需要四次挥手。 <strong>客户端为什么需要在 TIME-WAIT 状态等待 2MSL 时间才能进入 CLOSED 状态？</strong> 按照常理，在网络正常的情况下，四个报文段发送完后，双方就可以关闭连接进入 CLOSED 状态了，但是网络并不总是可靠的，如果客户端发送的 ACK 报文段丢失，服务器在接收不到 ACK 的情况下会一直重发 FIN 报文段，这显然不是我们想要的。因此客户端为了确保服务器收到了 ACK，会设置一个定时器，并在 TIME-WAIT 状态等待 2MSL 的时间，如果在此期间又收到了来自服务器的 FIN 报文段，那么客户端会重新设置计时器并再次等待 2MSL 的时间，如果在这段时间内没有收到来自服务器的 FIN 报文，那就说明服务器已经成功收到了 ACK 报文，此时客户端就可以进入 CLOSED 状态了。 <strong>简单来说，就是因为网络并不一定可靠，如果服务器没有接收到ACK报文会一直重发FIN，为了防止一直重发，就需要等待一段时间，如果没有等到就关闭，等到了重置2msl的时间</strong></p>',36)])])}const d=l(i,[["render",n]]);export{c as __pageData,d as default};
